import React, { useState } from "react";

function SOP() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule1 = async () => {
    setLoading(true);

    try {
      const res = await fetch("http://127.0.0.1:5000/module1");
      const data = await res.json();

      console.log("API Response:", data); // DEBUG

      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Backend not working");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 1</h2>

      <button onClick={runModule1}>Run Module 1</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>
          <h3>NPSV Length: {result.npsv_length}</h3>

          <h3>
            Segments Shape:{" "}
            {result.segments_shape
              ? result.segments_shape.join(", ")
              : "Not available"}
          </h3>

          <table border="1" style={{ margin: "auto" }}>
            <thead>
              <tr>
                <th>Index</th>
                <th>Value</th>
              </tr>
            </thead>
            <tbody>
              {result.npsv &&
                result.npsv.map((val, i) => (
                  <tr key={i}>
                    <td>{i}</td>
                    <td>{val.toFixed(4)}</td>
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default SOP;
